s:script.code:
import java.time.Instant

def SCIBACK_NS = 'urn:sciback:midpoint:person'
def AFFIL_OIDS = [
    '79ad22c7-b828-4b8c-a562-2ee01b214d7f',
    '94a03f65-e866-4d49-a996-26c4dc227413',
    '0da0b3b8-a93b-4765-ad71-30c535ff7512',
    '7d4e89fb-163c-478c-a224-4e4be733bc1b',
    '485dc678-94a5-4d20-9463-71568c625a33',
    '31f25974-62c9-404a-a038-b17a08059fe5'
] as Set

def VALID_AFFILIATIONS = ['STUDENT','FACULTY','STAFF','EMPLOYEE','ALUMNI','AFFILIATE-CU'] as Set

def user = input
def reasons = []

// PR-02: personalNumber no vacio
def pn = user.personalNumber?.orig
if (!pn || pn.trim() == '') {
    reasons << 'PR-02: personalNumber ausente o vacio'
}

// PR-03: >= 1 identityDocument con primary="true"
def hasPrimary = false
def primaryDocNumber = null
def primaryDocType = null
try {
    def containers = user.extension?.findContainers(
        new javax.xml.namespace.QName(SCIBACK_NS, 'identityDocuments')
    )
    if (containers) {
        containers.each { c ->
            def primVal = c?.findProperty(new javax.xml.namespace.QName(SCIBACK_NS, 'primary'))?.realValue
            if ('true' == primVal?.toString()) {
                hasPrimary = true
                primaryDocNumber = c?.findProperty(new javax.xml.namespace.QName(SCIBACK_NS, 'number'))?.realValue?.toString()
                primaryDocType   = c?.findProperty(new javax.xml.namespace.QName(SCIBACK_NS, 'type'))?.realValue?.toString()
            }
        }
    }
} catch (Exception e) {
    log.warn('PR-RECORD-REJECTION: error leyendo identityDocuments en {}: {}', user.name, e.message)
}
if (!hasPrimary) {
    reasons << 'PR-03: sin documento de identidad primario (primary=true)'
}

// PR-04: DNI valido (8 digitos numericos) -- aplica si tipo=DNI o tipo ausente
if (hasPrimary && primaryDocNumber != null) {
    def docType = primaryDocType?.toUpperCase() ?: 'DNI'
    if (docType == 'DNI' || docType == '') {
        if (!(primaryDocNumber ==~ /^\d{8}$/)) {
            reasons << "PR-04: numero DNI invalido '${primaryDocNumber}' (debe ser 8 digitos numericos)"
        }
    }
}

// PR-05: >= 1 rol R-Affiliation-* asignado
def hasAffil = user.assignment?.any { a ->
    a.targetRef?.oid in AFFIL_OIDS
}
if (!hasAffil) {
    reasons << 'PR-05: sin rol de afiliacion R-Affiliation-* asignado'
}

// PR-06: primaryAffiliation en vocabulario canonico
def primAffil = user.extension?.findProperty(
    new javax.xml.namespace.QName(SCIBACK_NS, 'primaryAffiliation')
)?.realValue?.toString()
if (!primAffil || !(primAffil.toUpperCase() in VALID_AFFILIATIONS)) {
    reasons << "PR-06: primaryAffiliation invalido o ausente ('${primAffil}'). Validos: ${VALID_AFFILIATIONS.sort().join('|')}"
}

// PR-07: emailAddress institucional (@upeu.edu.pe)
def email = user.emailAddress?.orig
if (!email || !email.endsWith('@upeu.edu.pe')) {
    reasons << "PR-07: emailAddress institucional ausente o invalido ('${email}')"
}

// PR-08a: givenName
if (!user.givenName?.orig || user.givenName.orig.trim() == '') {
    reasons << 'PR-08a: givenName ausente o vacio'
}
// PR-08b: familyName
if (!user.familyName?.orig || user.familyName.orig.trim() == '') {
    reasons << 'PR-08b: familyName ausente o vacio'
}

// Escribir resultados en extension
if (reasons) {
    def now = Instant.now().toString()
    log.info('PR-RECORD-REJECTION [{}]: {} fallos: {}', user.name, reasons.size(), reasons.join(' | '))

    def userOid = user.oid
    def userType = com.evolveum.midpoint.xml.ns._public.common.common_3.UserType.class
    def delta = prismContext.deltaFactory().object().createEmptyModifyDelta(userType, userOid)

    def rejReasonsPath = com.evolveum.midpoint.prism.path.ItemPath.create(
        'extension', new javax.xml.namespace.QName(SCIBACK_NS, 'rejectionReasons'))
    def rejAtPath = com.evolveum.midpoint.prism.path.ItemPath.create(
        'extension', new javax.xml.namespace.QName(SCIBACK_NS, 'rejectedAt'))
    def rejSrcPath = com.evolveum.midpoint.prism.path.ItemPath.create(
        'extension', new javax.xml.namespace.QName(SCIBACK_NS, 'rejectionSource'))

    delta.addModificationReplaceProperty(rejReasonsPath, reasons.toArray(new String[0]))
    delta.addModificationReplaceProperty(rejAtPath, now)
    delta.addModificationReplaceProperty(rejSrcPath, 'PR-RECORD-REJECTION@archetype-person')

    midpoint.applyDelta(delta)
} else {
    // Perfil completo: limpiar campos de rechazo si existian de iteracion anterior
    def rejReasonsQName = new javax.xml.namespace.QName(SCIBACK_NS, 'rejectionReasons')
    def hasOldReasons = user.extension?.findProperty(rejReasonsQName)?.realValue != null

    if (hasOldReasons) {
        log.info('PR-RECORD-REJECTION [{}]: perfil ahora completo -- limpiando campos de rechazo previos', user.name)
        def userType = com.evolveum.midpoint.xml.ns._public.common.common_3.UserType.class
        def delta = prismContext.deltaFactory().object().createEmptyModifyDelta(userType, user.oid)
        delta.addModificationReplaceProperty(com.evolveum.midpoint.prism.path.ItemPath.create(
            'extension', rejReasonsQName))
        delta.addModificationReplaceProperty(com.evolveum.midpoint.prism.path.ItemPath.create(
            'extension', new javax.xml.namespace.QName(SCIBACK_NS, 'rejectedAt')))
        delta.addModificationReplaceProperty(com.evolveum.midpoint.prism.path.ItemPath.create(
            'extension', new javax.xml.namespace.QName(SCIBACK_NS, 'rejectionSource')))
        midpoint.applyDelta(delta)
    } else {
        log.debug('PR-RECORD-REJECTION [{}]: perfil completo -- sin razones de rechazo', user.name)
    }
}
